package com.cognizant.springlearn.dao;
import java.util.*; import org.springframework.stereotype.Repository; import com.cognizant.springlearn.model.*;
@Repository public class EmployeeDao { public static final List<Employee> EMPLOYEE_LIST = new ArrayList<>(); static { Department tech=new Department(1,"Technology"); Department hr=new Department(2,"HR"); Skill java=new Skill(1,"Java"); Skill angular=new Skill(2,"Angular"); EMPLOYEE_LIST.add(new Employee(1,"John",80000,true,tech,List.of(java,angular))); EMPLOYEE_LIST.add(new Employee(2,"Ayush",75000,true,tech,List.of(java))); EMPLOYEE_LIST.add(new Employee(3,"Priya",65000,false,hr,List.of(angular))); EMPLOYEE_LIST.add(new Employee(4,"Rahul",70000,true,tech,List.of(java,angular))); } public List<Employee> getAllEmployees(){ return EMPLOYEE_LIST; } public Employee getEmployee(int id){ return EMPLOYEE_LIST.stream().filter(e -> e.getId()==id).findFirst().orElseThrow(); } }
